from dataclasses import dataclass, field
from datetime import date
from typing import Optional
from enum import Enum


class CompletionStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    PASSED = "passed"
    FAILED = "failed"


@dataclass
class ModuleAttempt:
    module_id: str
    started_date: date
    completed_date: Optional[date]
    status: CompletionStatus
    assessment_score: Optional[float]   # 0.0 - 1.0
    pass_threshold: float = 0.75


@dataclass
class LearnerRecord:
    employee_id: str
    role_category: str
    assigned_curriculum_id: str
    attempts: list[ModuleAttempt] = field(default_factory=list)

    def passed_modules(self) -> set[str]:
        return {a.module_id for a in self.attempts if a.status == CompletionStatus.PASSED}

    def completion_percentage(self, total_required: int) -> float:
        return len(self.passed_modules()) / total_required if total_required else 0.0

    def at_risk(self) -> bool:
        failed = [a for a in self.attempts if a.status == CompletionStatus.FAILED]
        return len(failed) >= 2

    def needs_support(self) -> list[str]:
        reasons = []
        if self.at_risk():
            reasons.append("Two or more failed attempts -- learning support recommended")
        in_progress = [a for a in self.attempts if a.status == CompletionStatus.IN_PROGRESS]
        for attempt in in_progress:
            if (date.today() - attempt.started_date).days > 14:
                reasons.append(
                    f"Module {attempt.module_id} in progress for > 14 days -- check for blockers"
                )
        return reasons


def cohort_readiness_report(records: list[LearnerRecord], total_required_modules: int) -> dict:
    ready = sum(
        1 for r in records
        if r.completion_percentage(total_required_modules) >= 1.0
    )
    at_risk_count = sum(1 for r in records if r.at_risk())
    avg_completion = (
        sum(r.completion_percentage(total_required_modules) for r in records) / len(records)
        if records else 0.0
    )
    return {
        "total_learners": len(records),
        "fully_ready": ready,
        "at_risk": at_risk_count,
        "avg_completion_pct": round(avg_completion * 100, 1),
        "go_live_gate": ready / len(records) >= 0.80 if records else False,
    }


